list:
button {
	cursor: pointer;
	font-size: 85%;
	font-weight: bold;
	color:darkslateblue;
}

.content-container {
	border: solid 1px rgb(0, 6, 85);
	padding: 2px;
	padding-left: 1px;
	background-color: white;
	position: absolute;
	top: 34px;
	bottom: 0;
	width : calc(100vw - 4px);
}

.owner_name {
	font-weight: bolder;
	color: rgb(30, 20, 95);
	font-style: normal;
	font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
	font-size: 91%;
}

.super-header {
	border: solid 1px rgb(223, 89, 11);
	padding: 2px;
	font-size: smaller;
	font-weight: 700;
	background-color: rgb(255, 254, 248);
	color: rgb(74, 83, 55);
	max-height:32px;
	width: 100%;
	}

